import{_ as e,o as l,c as t,ag as o}from"./chunks/framework.CTpQozEL.js";const m=JSON.parse('{"title":"상태 확인 (macOS)","description":"macOS 앱이 게이트웨이/Baileys 상태를 보고하는 방법","frontmatter":{"title":"상태 확인 (macOS)","description":"macOS 앱이 게이트웨이/Baileys 상태를 보고하는 방법"},"headers":[],"relativePath":"platforms/mac/health.md","filePath":"platforms/mac/health.md","lastUpdated":null}'),c={name:"platforms/mac/health.md"};function i(r,a,n,h,s,d){return l(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="macos에서-상태-확인" tabindex="-1">macOS에서 상태 확인 <a class="header-anchor" href="#macos에서-상태-확인" aria-label="Permalink to &quot;macOS에서 상태 확인&quot;">​</a></h1><p>메뉴 바 앱에서 연결된 채널이 정상인지 확인하는 방법입니다.</p><h2 id="메뉴-바" tabindex="-1">메뉴 바 <a class="header-anchor" href="#메뉴-바" aria-label="Permalink to &quot;메뉴 바&quot;">​</a></h2><ul><li>상태 점이 이제 Baileys 상태를 반영합니다: <ul><li>초록: 연결됨 + 최근 소켓 열림.</li><li>주황: 연결 중/재시도 중.</li><li>빨강: 로그아웃되었거나 프로브 실패.</li></ul></li><li>보조 줄에는 &quot;linked · auth 12m&quot;이 표시되거나 실패 이유가 표시됩니다.</li><li>&quot;Run Health Check&quot; 메뉴 항목이 주문형 프로브를 트리거합니다.</li></ul><h2 id="설정" tabindex="-1">설정 <a class="header-anchor" href="#설정" aria-label="Permalink to &quot;설정&quot;">​</a></h2><ul><li>General 탭에 상태 카드가 추가됩니다. 표시 내용: 연결된 인증 기간, 세션 저장소 경로/수, 마지막 확인 시간, 마지막 오류/상태 코드, Run Health Check / Reveal Logs 버튼.</li><li>캐시된 스냅샷을 사용하므로 UI가 즉시 로드되고 오프라인 시 안정적으로 대체됩니다.</li><li><strong>Channels 탭</strong>은 WhatsApp/Telegram의 채널 상태 + 제어 (로그인 QR, 로그아웃, 프로브, 마지막 연결 해제/오류)를 표시합니다.</li></ul><h2 id="프로브-작동-방식" tabindex="-1">프로브 작동 방식 <a class="header-anchor" href="#프로브-작동-방식" aria-label="Permalink to &quot;프로브 작동 방식&quot;">​</a></h2><ul><li>앱은 <code>ShellExecutor</code>를 통해 ~60초마다 및 주문형으로 <code>openclaw health --json</code>을 실행합니다. 프로브는 자격 증명을 로드하고 메시지를 보내지 않고 상태를 보고합니다.</li><li>플리커를 방지하기 위해 마지막 양호한 스냅샷과 마지막 오류를 별도로 캐시합니다. 각각의 타임스탬프를 표시합니다.</li></ul><h2 id="의심스러울-때" tabindex="-1">의심스러울 때 <a class="header-anchor" href="#의심스러울-때" aria-label="Permalink to &quot;의심스러울 때&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/health">게이트웨이 상태</a>의 CLI 흐름을 여전히 사용할 수 있습니다 (<code>openclaw status</code>, <code>openclaw status --deep</code>, <code>openclaw health --json</code>). <code>web-heartbeat</code> / <code>web-reconnect</code>에 대해 <code>/tmp/openclaw/openclaw-*.log</code>를 추적하십시오.</li></ul>',10)])])}const p=e(c,[["render",i]]);export{m as __pageData,p as default};
